SELECT type_id, SUM(usage_count) AS total_usage
FROM type_usage
GROUP BY type_id;

SELECT type_name
FROM data_types
WHERE size_bits = (SELECT MAX(size_bits) FROM data_types);

SELECT use_case_id, COUNT(*) AS recommended_data_types_count
FROM type_recommendations
GROUP BY use_case_id;

SELECT use_case_id, reason, alternative_types
FROM type_recommendations
WHERE use_case_id = 0;
